changeSet.sql:
CREATE INDEX IF NOT EXISTS otps_expires_at_idx
    ON users.otps(expires_at);

CREATE INDEX IF NOT EXISTS sessions_expires_at_idx
    ON users.sessions(expires_at);

CREATE INDEX IF NOT EXISTS sessions_revoked_at_idx
    ON users.sessions(revoked_at)
    WHERE revoked_at IS NOT NULL;

rollback.sql:
DROP INDEX IF EXISTS users.sessions_revoked_at_idx;
DROP INDEX IF EXISTS users.sessions_expires_at_idx;
DROP INDEX IF EXISTS users.otps_expires_at_idx;
